import 'dart:math';

import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

/// Auto-zoom configuration.
class AutoExploreConfig {
  static const double defaultMinZoom = 0.2;
  static const double defaultMaxZoom = 1e12;

  /// Minimum and maximum zoom targets for the auto cycle.
  final double minZoom;
  final double maxZoom;

  /// Peak zoom target starts from: baseZoom * [cycleMaxMultiplier], then gets
  /// clamped by smart precision limits per fractal module.
  final double cycleMaxMultiplier;

  /// Maximum zoom span per leg in log10 decades (e.g. 3.0 => up to 1000x).
  final double maxLegSpanDecades;

  /// Precision headroom under policy threshold to avoid probing unstable edges.
  final double precisionHeadroom;

  /// Duration for each zoom leg (in or out).
  final Duration travelDuration;

  /// Maximum multiplier for duration scaling on very large zoom spans.
  final double maxDurationScale;

  const AutoExploreConfig({
    this.minZoom = defaultMinZoom,
    this.maxZoom = defaultMaxZoom,
    this.cycleMaxMultiplier = 120.0,
    this.maxLegSpanDecades = 3.2,
    this.precisionHeadroom = 0.92,
    this.travelDuration = const Duration(milliseconds: 9000),
    this.maxDurationScale = 4.0,
  });
}

/// Speed bounds used by auto-explore playback.
///
/// Dart's [double.clamp] treats NaN as the upper bound. For playback speed,
/// invalid telemetry or UI state should fall back to neutral 1.0x instead of
/// silently selecting the fastest supported speed.
class AutoExploreSpeed {
  static const double min = 0.5;
  static const double neutral = 1.0;
  static const double max = 3.0;

  const AutoExploreSpeed._();

  static double normalize(double speed) {
    if (speed.isNaN) return neutral;
    return speed.clamp(min, max);
  }
}

/// Precision headroom used to keep auto-explore below renderer fallback edges.
///
/// Values above 1.0 would push candidates past the module precision threshold;
/// non-finite values must not rely on [double.clamp] because NaN clamps to the
/// upper bound and would silently promote targets to max zoom.
class AutoExplorePrecisionHeadroom {
  static const double neutral = 1.0;

  const AutoExplorePrecisionHeadroom._();

  static double normalize(double headroom) {
    if (!headroom.isFinite || headroom <= 0.0) return neutral;
    return headroom.clamp(0.0, neutral);
  }
}

/// Cycle shape used by auto-explore target planning.
///
/// Invalid multipliers or span limits can otherwise turn zoom-out floors into
/// max zooms or collapse peak candidates into NaN/minimum zooms. Keeping the
/// cycle shape explicit makes candidate planning replayable from config alone.
class AutoExploreCycleShape {
  final double cycleMaxMultiplier;
  final double maxLegSpanDecades;

  const AutoExploreCycleShape({
    required this.cycleMaxMultiplier,
    required this.maxLegSpanDecades,
  });

  factory AutoExploreCycleShape.fromConfig(AutoExploreConfig config) {
    return AutoExploreCycleShape(
      cycleMaxMultiplier: _finiteAboveNeutralOrDefault(
        config.cycleMaxMultiplier,
        const AutoExploreConfig().cycleMaxMultiplier,
      ),
      maxLegSpanDecades: _finiteNonNegativeOrDefault(
        config.maxLegSpanDecades,
        const AutoExploreConfig().maxLegSpanDecades,
      ),
    );
  }

  static double _finiteAboveNeutralOrDefault(double value, double fallback) {
    return value.isFinite && value > 1.0 ? value : fallback;
  }

  static double _finiteNonNegativeOrDefault(double value, double fallback) {
    return value.isFinite && value >= 0.0 ? value : fallback;
  }
}

/// Duration scaling used by auto-explore zoom legs.
///
/// Invalid scale factors can otherwise flow into [double.round], where NaN or
/// infinity throws instead of producing a replayable fallback duration.
class AutoExploreDurationScale {
  static const double neutral = 1.0;

  const AutoExploreDurationScale._();

  static double normalize(double scale) {
    if (!scale.isFinite || scale < neutral) return neutral;
    return scale;
  }
}

/// Zoom bounds used by auto-explore planning.
///
/// Dart's [double.clamp] treats NaN as the upper bound, which would turn a
/// corrupted/uninitialized zoom reading into an extreme deep-zoom target.
/// Keep sanitization explicit so candidate planning remains replayable.
class AutoExploreZoomBounds {
  final double minZoom;
  final double maxZoom;

  const AutoExploreZoomBounds({
    required this.minZoom,
    required this.maxZoom,
  });

  factory AutoExploreZoomBounds.fromConfig(AutoExploreConfig config) {
    final configuredMin = _positiveFiniteOrDefault(
      config.minZoom,
      AutoExploreConfig.defaultMinZoom,
    );
    final configuredMax = _positiveFiniteOrDefault(
      config.maxZoom,
      AutoExploreConfig.defaultMaxZoom,
    );

    return AutoExploreZoomBounds(
      minZoom: min(configuredMin, configuredMax),
      maxZoom: max(configuredMin, configuredMax),
    );
  }

  static double _positiveFiniteOrDefault(double value, double fallback) {
    return value.isFinite && value > 0.0 ? value : fallback;
  }

  double clamp(double zoom) {
    if (zoom.isNaN) return minZoom;
    return zoom.clamp(minZoom, maxZoom);
  }
}

/// Sanitized zoom leg used for replayable duration/interpolation math.
class AutoExploreZoomLeg {
  final double startZoom;
  final double endZoom;

  const AutoExploreZoomLeg({
    required this.startZoom,
    required this.endZoom,
  });

  factory AutoExploreZoomLeg.fromBounds({
    required AutoExploreZoomBounds bounds,
    required double startZoom,
    required double endZoom,
  }) {
    return AutoExploreZoomLeg(
      startZoom: bounds.clamp(startZoom),
      endZoom: bounds.clamp(endZoom),
    );
  }

  double get spanDecades {
    final ratio = max(startZoom, endZoom) / min(startZoom, endZoom);
    return ratio <= 1.0 ? 0.0 : (log(ratio) / ln10);
  }

  double interpolate(double t) {
    final progress = t.isNaN ? 0.0 : t.clamp(0.0, 1.0);
    return startZoom * pow(endZoom / startZoom, progress).toDouble();
  }
}

/// Pure zoom-planning logic for [AutoExploreService].
///
/// Keeping target selection side-effect free makes the precision assumptions
/// replayable in tests without constructing timers or a renderer controller.
class AutoExploreZoomPlanner {
  final AutoExploreConfig config;
  final DeepZoomPrecisionPolicy precisionPolicy;

  const AutoExploreZoomPlanner({
    required this.config,
    this.precisionPolicy = const DeepZoomPrecisionPolicy(),
  });

  AutoExploreZoomBounds get _bounds => AutoExploreZoomBounds.fromConfig(config);
  AutoExploreCycleShape get _cycleShape =>
      AutoExploreCycleShape.fromConfig(config);

  double clampZoom(double zoom) => _bounds.clamp(zoom);

  double hardMaxZoomFor(String moduleId) {
    final headroom = AutoExplorePrecisionHeadroom.normalize(
      config.precisionHeadroom,
    );
    final safeThreshold = precisionPolicy.thresholdFor(moduleId) * headroom;
    return _bounds.clamp(safeThreshold);
  }

  double computePeakZoom({
    required double baseZoom,
    required String moduleId,
  }) {
    final base = clampZoom(baseZoom);
    final hardMax = hardMaxZoomFor(moduleId);
    final minPeak = clampZoom(base * 1.25);
    final cycleShape = _cycleShape;
    final configuredPeak = clampZoom(base * cycleShape.cycleMaxMultiplier);

    final maxSpanRatio = pow(10.0, cycleShape.maxLegSpanDecades).toDouble();
    final spanLimitedPeak = clampZoom(base * maxSpanRatio);

    final desiredPeak = min(configuredPeak, spanLimitedPeak);
    final unclampedPeak = max(minPeak, min(desiredPeak, hardMax));
    return min(unclampedPeak, hardMax);
  }

  double computeFloorZoom(double baseZoom) {
    final bounds = _bounds;
    final base = bounds.clamp(baseZoom);
    final contextualFloor = base / _cycleShape.cycleMaxMultiplier;
    return bounds.clamp(max(bounds.minZoom, contextualFloor));
  }

  double nextTargetZoom({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    final current = clampZoom(currentZoom);
    final baseZoom = clampZoom(cycleBaseZoom ?? current);
    final peakZoom = computePeakZoom(baseZoom: baseZoom, moduleId: moduleId);
    final floorZoom = computeFloorZoom(baseZoom);

    if ((peakZoom - floorZoom).abs() < 1e-9) {
      return baseZoom;
    }

    return zoomingIn ? peakZoom : floorZoom;
  }

  Duration durationForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: startZoom,
      endZoom: endZoom,
    );
    final effectiveSpeed = _effectiveSpeed(speed);

    final durationScale = AutoExploreDurationScale.normalize(
      config.maxDurationScale,
    );
    final normalized = (leg.spanDecades / 1.6).clamp(0.0, 1.0);
    final scale = 1.0 + normalized * (durationScale - 1.0);

    final ms = (config.travelDuration.inMilliseconds * scale).round();
    final scaledMs = (ms / effectiveSpeed).round();
    return Duration(milliseconds: max(1, scaledMs));
  }

  double _effectiveSpeed(double speed) => AutoExploreSpeed.normalize(speed);

  double interpolateZoom(double start, double end, double t) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: _bounds,
      startZoom: start,
      endZoom: end,
    );
    return leg.interpolate(t);
  }
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreZoomPlanner', () {
    const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

    test('keeps peak zoom under module precision headroom', () {
      // Unknown modules use the default 1e7 precision threshold, so headroom is
      // 9.2e6. A base zoom near that edge used to let the 1.25x minimum peak
      // overrun the module-aware hard max.
      const moduleId = 'unknown_orbit_module';
      const baseZoom = 9.0e6;

      final hardMax = planner.hardMaxZoomFor(moduleId);
      final peakZoom = planner.computePeakZoom(
        baseZoom: baseZoom,
        moduleId: moduleId,
      );

      expect(hardMax, 9.2e6);
      expect(peakZoom, hardMax);
      expect(peakZoom, lessThanOrEqualTo(hardMax));
    });

    test('does not promote invalid precision headroom to max zoom', () {
      const planner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(precisionHeadroom: double.nan),
      );

      expect(planner.hardMaxZoomFor('unknown_orbit_module'), 1e7);
      expect(
        planner.computePeakZoom(
          baseZoom: 9.0e6,
          moduleId: 'unknown_orbit_module',
        ),
        lessThanOrEqualTo(1e7),
      );
    });

    test('plans zoom-in and zoom-out targets from the same cycle base', () {
      const baseZoom = 10.0;

      expect(
        planner.nextTargetZoom(
          currentZoom: 12.0,
          cycleBaseZoom: baseZoom,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        1200.0,
      );
      expect(
        planner.nextTargetZoom(
          currentZoom: 12.0,
          cycleBaseZoom: baseZoom,
          zoomingIn: false,
          moduleId: 'mandelbrot',
        ),
        AutoExploreConfig().minZoom,
      );
    });

    test('scales leg duration by zoom span and speed', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const fastPlanner = AutoExploreZoomPlanner(config: config);

      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 2.0,
        ),
        const Duration(milliseconds: 500),
      );
      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1e6,
          speed: 2.0,
        ),
        const Duration(milliseconds: 2000),
      );
    });

    test('normalizes invalid speed candidates before duration scaling', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(AutoExploreSpeed.normalize(0.0), 0.5);
      expect(AutoExploreSpeed.normalize(double.nan), 1.0);

      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 0.0,
        ),
        const Duration(milliseconds: 2000),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: double.nan,
        ),
        const Duration(milliseconds: 1000),
      );
    });

    test('does not treat NaN zoom as maximum zoom', () {
      const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

      expect(planner.clampZoom(double.nan), AutoExploreConfig().minZoom);
      expect(
        planner.nextTargetZoom(
          currentZoom: double.nan,
          cycleBaseZoom: null,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        24.0,
      );
    });

    test('normalizes malformed zoom bounds before clamping candidates', () {
      const reversedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 100.0, maxZoom: 1.0),
      );
      const invalidPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: double.nan, maxZoom: -1.0),
      );

      expect(reversedPlanner.clampZoom(0.5), 1.0);
      expect(reversedPlanner.clampZoom(200.0), 100.0);
      expect(invalidPlanner.clampZoom(double.nan), 0.2);
      expect(invalidPlanner.clampZoom(double.infinity), 1e12);
    });

    test('uses normalized zoom bounds for precision hard max planning', () {
      const reversedPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: 100.0, maxZoom: 1.0),
      );
      const invalidPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(minZoom: double.nan, maxZoom: -1.0),
      );

      expect(reversedPlanner.hardMaxZoomFor('unknown_orbit_module'), 100.0);
      expect(invalidPlanner.hardMaxZoomFor('unknown_orbit_module'), 9.2e6);
      expect(
        reversedPlanner.nextTargetZoom(
          currentZoom: 10.0,
          cycleBaseZoom: null,
          zoomingIn: true,
          moduleId: 'unknown_orbit_module',
        ),
        100.0,
      );
    });

    test('sanitizes invalid zoom endpoints before duration math', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(
        planner.durationForZoomLeg(
          startZoom: double.nan,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 2311),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: double.infinity,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 4000),
      );
    });

    test('normalizes invalid cycle shape before target planning', () {
      const zeroMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: 0.0),
      );
      const nanMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: double.nan),
      );
      const infiniteMultiplierPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(cycleMaxMultiplier: double.infinity),
      );
      const nanSpanPlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(maxLegSpanDecades: double.nan),
      );

      expect(
        zeroMultiplierPlanner.nextTargetZoom(
          currentZoom: 10.0,
          cycleBaseZoom: 10.0,
          zoomingIn: false,
          moduleId: 'mandelbrot',
        ),
        AutoExploreConfig().minZoom,
      );
      for (final planner in [
        nanMultiplierPlanner,
        infiniteMultiplierPlanner,
        nanSpanPlanner,
      ]) {
        expect(
          planner.computePeakZoom(baseZoom: 10.0, moduleId: 'mandelbrot'),
          1200.0,
        );
      }

      expect(
        AutoExploreCycleShape.fromConfig(
          const AutoExploreConfig(cycleMaxMultiplier: 0.0),
        ).cycleMaxMultiplier,
        AutoExploreConfig().cycleMaxMultiplier,
      );
    });

    test('sanitizes invalid duration scale before rounding milliseconds', () {
      const nanScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.nan,
        ),
      );
      const infiniteScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: double.infinity,
        ),
      );
      const belowNeutralScalePlanner = AutoExploreZoomPlanner(
        config: AutoExploreConfig(
          travelDuration: Duration(milliseconds: 1000),
          maxDurationScale: 0.0,
        ),
      );

      for (final planner in [
        nanScalePlanner,
        infiniteScalePlanner,
        belowNeutralScalePlanner,
      ]) {
        expect(
          planner.durationForZoomLeg(
            startZoom: 1.0,
            endZoom: 1e6,
            speed: 1.0,
          ),
          const Duration(milliseconds: 1000),
        );
      }
    });
  });
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return thresholdsFor(moduleId).shouldUseCpuFallback(zoom);
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return thresholdsFor(moduleId).shouldUseDoubleFloat(zoom);
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
bool _isSameHysteresisStreak({
  required String? previousModuleId,
  required String moduleId,
}) =>
    previousModuleId == moduleId;

class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  String? _trackedModuleId;
  int _aboveThresholdCount = 0;
  bool _cpuActive = false;

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    if (!_isSameHysteresisStreak(
      previousModuleId: _trackedModuleId,
      moduleId: moduleId,
    )) {
      _aboveThresholdCount = 0;
      _cpuActive = false;
      _trackedModuleId = moduleId;
    }

    if (overThreshold) {
      _aboveThresholdCount++;
      if (_aboveThresholdCount >= policy.hysteresisFrames) {
        _cpuActive = true;
      }
    } else {
      // Immediately drop back to GPU on zoom-out — no delay needed.
      _aboveThresholdCount = 0;
      _cpuActive = false;
    }

    return _cpuActive;
  }

  void reset() {
    _trackedModuleId = null;
    _aboveThresholdCount = 0;
    _cpuActive = false;
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

void main() {
  const policy = DeepZoomPrecisionPolicy();

  group('DeepZoomPrecisionPolicy.thresholdsFor', () {
    test('exposes contiguous Mandelbrot df2 to CPU fallback boundaries', () {
      final thresholds = policy.thresholdsFor('mandelbrot');

      expect(thresholds.supportsDoubleFloat, isTrue);
      expect(thresholds.doubleFloatLowerZoom, 5e6);
      expect(thresholds.doubleFloatUpperZoom, thresholds.cpuFallbackZoom);
      expect(thresholds.shouldUseDoubleFloat(1e11), isTrue);
      expect(
        thresholds.shouldUseDoubleFloat(thresholds.cpuFallbackZoom),
        isFalse,
      );
      expect(
        thresholds.shouldUseCpuFallback(thresholds.cpuFallbackZoom),
        isTrue,
      );
    });

    test('exposes default thresholds without a double-float range', () {
      final thresholds = policy.thresholdsFor('unknown_fractal');

      expect(thresholds.cpuFallbackZoom, 1e7);
      expect(thresholds.supportsDoubleFloat, isFalse);
      expect(thresholds.shouldUseDoubleFloat(1e10), isFalse);
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseCpuFallback', () {
    test('returns false for mandelbrot at zoom 1e6', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e6),
        isFalse,
      );
    });

    test('returns true for mandelbrot at zoom 1e15', () {
      expect(
        policy.shouldUseCpuFallback(moduleId: 'mandelbrot', zoom: 1e15),
        isTrue,
      );
    });

    test('uses default threshold for unknown module', () {
      // Default threshold is 1e7; zoom just below should be false.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 9.9e6),
        isFalse,
      );
      // At or above default threshold (1e7) should be true.
      expect(
        policy.shouldUseCpuFallback(moduleId: 'unknown_fractal', zoom: 1e7),
        isTrue,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.shouldUseDoubleFloat', () {
    test('returns true for mandelbrot in df2 range', () {
      // df2 range: [5e6, 1e12)
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 5e6),
        isTrue,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e10),
        isTrue,
      );
    });

    test('returns false for non-mandelbrot modules', () {
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'julia', zoom: 1e10),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'burning_ship', zoom: 1e10),
        isFalse,
      );
    });

    test('returns false below df2 lower threshold', () {
      // Below 5e6 the standard float32 shader is sufficient.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e5),
        isFalse,
      );
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 4.9e6),
        isFalse,
      );
    });

    test('returns false at or above df2 upper threshold', () {
      // At 1e12 CPU fallback takes over; df2 should not be active.
      expect(
        policy.shouldUseDoubleFloat(moduleId: 'mandelbrot', zoom: 1e12),
        isFalse,
      );
    });
  });

  group('DeepZoomPrecisionPolicy.scaledGpuIterations', () {
    test('returns base at zoom 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0),
        equals(256),
      );
    });

    test('returns base at zoom below 1', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: 0.5),
        equals(256),
      );
    });

    test('increases with zoom depth', () {
      final atZoom1 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1.0);
      final atZoom1e6 =
          policy.scaledGpuIterations(baseIterations: 256, zoom: 1e6);
      expect(atZoom1e6, greaterThan(atZoom1));
    });

    test('clamps to gpuMaxIterations', () {
      // Very high base + very high zoom should be clamped.
      final result = policy.scaledGpuIterations(
        baseIterations: DeepZoomPrecisionPolicy.gpuMaxIterations,
        zoom: 1e30,
      );
      expect(result, equals(DeepZoomPrecisionPolicy.gpuMaxIterations));
    });

    test('clamps low base to minimum of 4', () {
      final result = policy.scaledGpuIterations(baseIterations: 1, zoom: 1.0);
      expect(result, equals(4));
    });

    test('treats non-finite zoom values as bounded inputs', () {
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.nan),
        equals(256),
      );
      expect(
        policy.scaledGpuIterations(baseIterations: 256, zoom: double.infinity),
        equals(DeepZoomPrecisionPolicy.gpuMaxIterations),
      );
      expect(
        policy.scaledGpuIterations(
          baseIterations: 256,
          zoom: double.negativeInfinity,
        ),
        equals(256),
      );
    });
  });

  group('DeepZoomHysteresis', () {
    test('does not activate CPU until hysteresisFrames consecutive frames', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      // mandelbrot CPU threshold is 1e12; zoom 2e12 is above it.
      const moduleId = 'mandelbrot';
      const highZoom = 2e12;
      final frames = policy.hysteresisFrames;

      // All frames before the last should still return false.
      for (var i = 0; i < frames - 1; i++) {
        expect(
          hysteresis.update(moduleId: moduleId, zoom: highZoom),
          isFalse,
          reason: 'frame $i should not activate CPU yet',
        );
      }

      // The hysteresisFrames-th frame should activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isTrue,
      );
    });

    test('drops back to GPU immediately when zoom falls below threshold', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      const lowZoom = 1.0;
      final frames = policy.hysteresisFrames;

      // Trigger CPU mode.
      for (var i = 0; i < frames; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      // A single below-threshold update drops back to GPU.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: lowZoom),
        isFalse,
      );
    });

    test('does not carry above-threshold count across module changes', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);

      expect(
        hysteresis.update(moduleId: 'julia', zoom: 2e9),
        isFalse,
        reason: 'first Julia deep-zoom frame should only prime hysteresis',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isFalse,
        reason: 'first Mandelbrot deep-zoom frame must not inherit Julia count',
      );

      expect(
        hysteresis.update(moduleId: 'mandelbrot', zoom: 2e14),
        isTrue,
        reason: 'second consecutive Mandelbrot deep-zoom frame activates CPU',
      );
    });

    test('reset clears state so hysteresis counter restarts', () {
      final hysteresis = DeepZoomHysteresis(policy: policy);
      const moduleId = 'mandelbrot';
      const highZoom = 2e14;
      final frames = policy.hysteresisFrames;

      // Build up to just before activation.
      for (var i = 0; i < frames - 1; i++) {
        hysteresis.update(moduleId: moduleId, zoom: highZoom);
      }

      hysteresis.reset();

      // After reset, the counter is zero; a single update should not activate.
      expect(
        hysteresis.update(moduleId: moduleId, zoom: highZoom),
        isFalse,
      );
    });
  });
}

import 'package:vector_math/vector_math.dart' show Vector2;

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = viewPan.x,
        centerY = viewPan.y,
        scale = 1.5 / (viewZoom <= 0 ? 1.0 : viewZoom),
        aspect = height == 0 ? 1.0 : width / height;

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    if (extent <= 1) return 0.0;
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final subPixel = pixel + (sample + 0.5) / safeSamples;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
