  group('FractalController view input sanitization', () {
    test('ignores NaN zoom instead of promoting it to max zoom', () {
      final controller = FractalController(ModuleRegistry());
      controller.updateZoom(42.0);

      controller.updateZoom(double.nan);

      expect(controller.view.zoom, 42.0);
    });

    test('preserves previous pan components when candidates are NaN', () {
      final controller = FractalController(ModuleRegistry());
      controller.updatePan(Vector2(1.25, -1.5));

      controller.updatePan(Vector2(double.nan, 2.0));

      expect(controller.view.pan.x, 1.25);
      expect(controller.view.pan.y, 2.0);
    });
  });
}

